-- Session 5 cleanup: replace Green Acres' picsum.photos placeholder
-- URLs with real images uploaded through the actual compress -> blur ->
-- Storage pipeline (via the kitchen-sink harness), and clear Kings Court's
-- picsum URLs back to empty (no real replacement photos for it) — so
-- picsum.photos can be safely removed from next.config.ts's remotePatterns
-- without breaking any live page.

update public.hostels
set images = '[{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/c8479823-755d-41e4-b51e-7ac1807561a9.webp","blurDataURL":"data:image/webp;base64,"},{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/0032d260-1c2e-4118-b501-133fcd54c9bd.webp","blurDataURL":"data:image/webp;base64,"},{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/dc6c1bfc-51d6-4782-a104-59e9a252acbf.webp","blurDataURL":"data:image/webp;base64,"}]'::jsonb
where name = 'Green Acres Hostel';

update public.hostels
set room_types = jsonb_build_array(
  jsonb_build_object('type', '1_in_room', 'price', 3200, 'images', '[{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/c8479823-755d-41e4-b51e-7ac1807561a9.webp","blurDataURL":"data:image/webp;base64,"},{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/0032d260-1c2e-4118-b501-133fcd54c9bd.webp","blurDataURL":"data:image/webp;base64,"}]'::jsonb),
  jsonb_build_object('type', '2_in_room', 'price', 2200, 'images', '[{"url":"https://ebdmqflfnsqpaujhezgw.supabase.co/storage/v1/object/public/hostel-images/dc6c1bfc-51d6-4782-a104-59e9a252acbf.webp","blurDataURL":"data:image/webp;base64,"}]'::jsonb)
)
where name = 'Green Acres Hostel';

update public.hostels
set images = '[]'::jsonb
where name = 'Kings Court Hostel';

update public.hostels
set room_types = jsonb_build_array(
  jsonb_build_object('type', '2_in_room', 'price', 1800, 'images', '[]'::jsonb)
)
where name = 'Kings Court Hostel';
